var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"다이브 아웃 완료.","JPN":"ダイブアウト完了。","ENG":"Dive-out completed.","TWN":"躍出完畢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L6_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"매복에 대비해 즉시 위상 장벽을 전개합니다.","JPN":"待ち伏せに備えてただちに位相防壁を展開します。","ENG":"Casting a phase barrier in case of possible ambush...","TWN":"小心埋伏，立刻打開屏障。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"포드가 추락한 위치를 확인하세요. 파악되는 대로 단거리 도약을 통해 진입합니다.","JPN":"ポッドが墜落した位置を確認してください。把握でき次第、短距離跳躍で進入します。","ENG":"Check the pod's landing location. We'll make a short leap to get there.","TWN":"請確認艙降落的位置，確認到後立刻透過短距離跳躍進入。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"여기가 서브스톰이군요.","JPN":"ここがサブストームですね。","ENG":"This is Substorm.","TWN":"這裡就是次級風暴嗎？！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이렇게 이면세계 깊숙한 곳에서 사람들이 살고 있다니…… 신기해요.","JPN":"こんな裏世界の奥深いところに人が住んでいるとは……不思議ですね。","ENG":"I can't believe some people live in the depths of the Counterside.","TWN":"竟然有人居住在異界這麼深的地方……好奇妙。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하늘도 우주 같아서, 꼭 달기지에 온 기분이에요.","JPN":"空も宇宙みたいですし、まるで月面基地に来ている気分です。","ENG":"The sky above looks like outer space. I feel like I'm on a moon base.","TWN":"天空長得好像宇宙，感覺就像來到月亮基地一樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"보이는 것만큼 아름답기만 한 곳은 아닙니다, 아가씨.","JPN":"見た目ほど美しい場所ではありませんよ、お嬢様。","ENG":"This place is not as beautiful as it looks, Miss Jia.","TWN":"小姐，這裡並非像妳眼睛看到的那般美好。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이면세계에 이렇게 거대한 시설을 세우는 동안, 그들에게 붙잡힌 기술자들이 수없이 희생되어야 했으니까요. ","JPN":"裏世界にこんなに巨大な施設を建てる間にも、\\n彼らに囚われた技術者が数え切れないほど犠牲になりましたから。","ENG":"The pirates sacrificed countless technicians to build such a big facility on the Counterside. ","TWN":"要在異界裡進行如此浩大的工程，也就表示被犧牲的研究人員難以計數。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그렇군요……","JPN":"そうですね……","ENG":"I see...","TWN":"原來是這樣……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그럼 왜 그 해적 분들은 이런 곳에 건물을 짓고 사는 건가요?","JPN":"ところで海賊たちはなぜこんな所に暮らしているんですか？","ENG":"But why did the pirates decide to build their home in a place like this?","TWN":"但那些海盜為什麼要在這種地方蓋建築物，住在這裡呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"관리국의 감시를 피해 이면세계의 유물을 파헤치고 연구하기 위해서입니다.","JPN":"管理局の監視を避けながら裏世界の遺物を掘り起こして研究するためです。","ENG":"To excavate and study Artifacts on the Counterside without detection from the Administration.","TWN":"他們想躲避管理局的監視，挖掘異界的遺物進行研究。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이런 고심도일수록 더 진귀한 것들이 발견되니까요.","JPN":"ここのように高深度になるほど、より珍しいものが発見されますから。","ENG":"The deeper you go, the more valuable things you can find.","TWN":"因為越深的地方，發現的東西就越稀有。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"빨리 움직여! 머리를 새로운 몸체에 연결하는 거다! 시뮬레이션은 생략해!","JPN":"さっさと動け！　頭部を新しい胴体に繋げるんだ！　シミュレーションは省略しろ！","ENG":"Get moving! Connect the head to the new body! Skip simulations!","TWN":"動作快！將頭連接到新的主體！模擬就省了！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ENGINEER_SCAVENGER_C_NULL","text":{"KOREA":"몸체의 가동 점검 완료! 머리 동기화 수준 81%!","JPN":"胴体の稼働点検完了！　頭部同期化レベル81％！","ENG":"Body's mobility checked! Head synch level: 81%!","TWN":"主體的啟動維護完成！頭重置程度 81%！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ENGINEER_SCAVENGER_C_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_15"},{"id":"L27_1","type":"dialog","speaker":"ENGINEER_SCAVENGER_F_NULL","text":{"KOREA":"무기 점검 끝! 유압장치와 반중력장 정상 동작 중!","JPN":"武器点検終了！　油圧装置と反重力場正常動作中！","ENG":"Weapons checked! Hydraulics and anti-gravitational field checked!","TWN":"武器維護結束！液壓裝置和反重力正常運作中！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ENGINEER_SCAVENGER_F_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_03"},{"id":"L29_1","type":"dialog","speaker":"ENGINEER_SCAVENGER_H_NULL","text":{"KOREA":"연결 반응 확인! 이상 무! 브레인 컨트롤 시스템, 올 그린!","JPN":"接続反応確認！　異常なし！　ブレーンコントロールシステム、オールグリーン！","ENG":"Connection response checked! Everything's good to go. Brain control system, all green lights!","TWN":"連接反應確認！無異常！腦控制系統正常！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ENGINEER_SCAVENGER_H_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_22"},{"id":"L34_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"실장님! 이볼브 원의 신호를 찾았습니다!","JPN":"室長！　イボルブ・ワンの信号が見つかりました！","ENG":"Chief! We've found the Evolved One's signals!","TWN":"室長！找到Evolved One的訊號了！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"좋습니다. 당장 이동하죠.","JPN":"よし、すぐ移動しましょう。","ENG":"Good, let's move.","TWN":"很好！立刻出發！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"잠깐……","JPN":"お待ちを……","ENG":"Wait...","TWN":"等一下……"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"신호가 움직입니다!","JPN":"信号が動き出しました！","ENG":"The signals are moving.","TWN":"訊號移動了！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"저희 함선이 있는 방향으로 오고 있습니다!","JPN":"この艦船の方向に動いています！","ENG":"They're coming toward us!","TWN":"訊號正朝我們艦船的方向移動！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"뭐라고요?","JPN":"なんですって？","ENG":"What?","TWN":"妳說什麼？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"하, 함선 장갑에 측정 불가능한 피해!","JPN":"か、艦船装甲に測定不可のダメージ発生！","ENG":"I-immeasurable damage to the ship armor!","TWN":"艦…艦船裝甲受到無法測量的傷害！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L17_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"동력부 손상! 회피기동이 불가능합니다!","JPN":"動力部損傷！　回避行動が不可能です！","ENG":"Engine damaged! Evasive maneuvers impossible!","TWN":"動力裝置受到毀損！無法啟動閃避！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아가씨! 괜찮으세요?","JPN":"お嬢様！　大丈夫ですか？","ENG":"Miss Jia, are you okay?","TWN":"小姐！妳還好嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네, 덕분에요.","JPN":"はい、おかげさまで。","ENG":"Yes, thank you.","TWN":"我沒事。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그런데 저건…… 아까 그 로봇?","JPN":"ところであれは……さっきのロボット？","ENG":"By the way, that... isn't it the same robot?","TWN":"不過那是……剛剛的機器人？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"생김새는 비슷하지만 아닙니다! 출력계수가 차원이 달라요!","JPN":"見た目は似ていますが違います！　出力係数が段違いです！","ENG":"No. It looks similar, but it's not the same. Its output coefficient is off the chart!","TWN":"不同隻，只是外表長得像而已！他們的輸出率很明顯不一樣！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"다음 공격을 받게 되면 이대로 전멸입니다!","JPN":"次の攻撃を受けたらこのまま全滅です！","ENG":"If we're attacked again, it'll be the end of us!","TWN":"只要再受到一次攻擊，我們就會全軍覆沒的！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"전쟁, 파괴, 죽음…….","JPN":"戦争、破壊、死……","ENG":"War, destruction, death...","TWN":"戰爭、毀壞、死亡……"},"stage":{"bg":"SS_SCAVENGER_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"그 모든 것들은 그저 진화를 위한 거름에 지나지 않는다.","JPN":"そのすべては進化のための肥やしに過ぎない。","ENG":"All that is mere fertilizer for evolution.","TWN":"這些都不過是進化的養分而已。"},"stage":{"bg":"SS_SCAVENGER_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"오랜만이다, 나를 가두었던 자들이여.","JPN":"久々だな、私を閉じ込めた者たちよ。","ENG":"Long time, no see, my captors.","TWN":"久違了，將我囚禁的人們。"},"stage":{"bg":"SS_SCAVENGER_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"나를 가두고 연구하여, 충분한 진화를 이루었기를 바란다.","JPN":"私を閉じ込めて研究し、十分な進化を遂げていることを願う。","ENG":"I hope you achieved ample evolution while you had me imprisoned.","TWN":"希望你們將我囚禁進行研究時，有完成充分的進化。"},"stage":{"bg":"SS_SCAVENGER_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"그렇지 않으면…… 너희는 오늘. 거름이 될 테니까.","JPN":"そうでなければ……お前たちはこれより、肥やしとなる。","ENG":"Otherwise... you'll become fertilizer today.","TWN":"沒有的話……那今天就是你們成為養分日子。"},"stage":{"bg":"SS_SCAVENGER_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"도망칠 곳은. 없다.","JPN":"逃げ場などない。","ENG":"There's nowhere to run.","TWN":"一個也別想逃。"},"stage":{"bg":"SS_SCAVENGER_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"너희들이 살아남을 만한 가치가 있는지, 내가 판단해 주겠다.","JPN":"お前たちに生き延びる価値があるのか、私が判断してやる。","ENG":"I'll judge if you deserve to live.","TWN":"至於你們有留下來的價值嗎？這一點由我來判斷！"},"stage":{"bg":"SS_SCAVENGER_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};